using Hospital.Domain.Entities;

namespace Hospital.Application.Interfaces;

public interface IPatientService
{
    Task<IEnumerable<Patient>> GetAllActiveAsync();
    Task<IEnumerable<Patient>> GetActiveByDoctorIdAsync(int doctorId);
    Task ProcessPatientsAsync(IEnumerable<int> patientIds);
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;
using Hospital.Domain.Interfaces;

namespace Hospital.Application.Services;

public class ApointmentService : IApointmentService
{
    private readonly IApointmentRepository _apointmentRepository;
    private readonly IPatientRepository _patientRepository;

    public ApointmentService(IApointmentRepository apointmentRepository, IPatientRepository patientRepository)
    {
        _apointmentRepository = apointmentRepository;
        _patientRepository = patientRepository;
    }

    public async Task ScheduleAppointmentAsync(int patientId, int doctorId, DateTime scheduledAt)
    {
        var patient = await _patientRepository.GetByIdAsync(patientId);
        if (patient is null)
        {
            throw new InvalidOperationException($"Patient {patientId} not found.");
        }

        var hasConflict = await _apointmentRepository.DoctorHasAppointmentAsync(doctorId, scheduledAt);
        if (hasConflict)
        {
            throw new InvalidOperationException("Doctor already has an appointment at this time.");
        }

        var apointment = new Apointment
        {
            PatientId = patientId,
            DoctorId = doctorId,
            ScheduledAt = scheduledAt,
            Status = "Scheduled"
        };

        await _apointmentRepository.AddAsync(apointment);
    }

    public async Task TransferPatientAsync(int patientId, int newDoctorId, DateTime scheduledAt)
    {
        var patientApointments = await _apointmentRepository.GetByPatientIdAsync(patientId);
        var activeApointment = patientApointments
            .Where(a => string.Equals(a.Status, "Scheduled", StringComparison.OrdinalIgnoreCase))
            .OrderByDescending(a => a.ScheduledAt)
            .FirstOrDefault();

        if (activeApointment is not null)
        {
            await _apointmentRepository.UpdateStatusAsync(activeApointment.Id, "Transferred");
        }

        await ScheduleAppointmentAsync(patientId, newDoctorId, scheduledAt);
    }
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;
using Hospital.Domain.Interfaces;

namespace Hospital.Application.Services;

public class ApointmentService : IApointmentService
{
    private readonly IApointmentRepository _apointmentRepository;
    private readonly IPatientRepository _patientRepository;

    public ApointmentService(IApointmentRepository apointmentRepository, IPatientRepository patientRepository)
    {
        _apointmentRepository = apointmentRepository;
        _patientRepository = patientRepository;
    }

    public async Task ScheduleAppointmentAsync(int patientId, int doctorId, DateTime scheduledAt)
    {
        if (patientId <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(patientId), "PatientId must be greater than 0.");
        }

        if (doctorId <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(doctorId), "DoctorId must be greater than 0.");
        }

        if (scheduledAt == default)
        {
            throw new ArgumentException("ScheduledAt is required.", nameof(scheduledAt));
        }

        var patient = await _patientRepository.GetByIdAsync(patientId);
        if (patient is null)
        {
            throw new InvalidOperationException($"Patient {patientId} not found.");
        }

        var hasConflict = await _apointmentRepository.DoctorHasAppointmentAsync(doctorId, scheduledAt);
        if (hasConflict)
        {
            throw new InvalidOperationException("Doctor already has an appointment at this time.");
        }

        var apointment = new Apointment
        {
            PatientId = patientId,
            DoctorId = doctorId,
            ScheduledAt = scheduledAt,
            Status = "Scheduled"
        };

        await _apointmentRepository.AddAsync(apointment);
    }

    public async Task TransferPatientAsync(int patientId, int newDoctorId, DateTime scheduledAt)
    {
        if (patientId <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(patientId), "PatientId must be greater than 0.");
        }

        if (newDoctorId <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(newDoctorId), "NewDoctorId must be greater than 0.");
        }

        if (scheduledAt == default)
        {
            throw new ArgumentException("ScheduledAt is required.", nameof(scheduledAt));
        }

        var patientApointments = await _apointmentRepository.GetByPatientIdAsync(patientId);
        var activeApointment = patientApointments
            .Where(a => string.Equals(a.Status, "Scheduled", StringComparison.OrdinalIgnoreCase))
            .OrderByDescending(a => a.ScheduledAt)
            .FirstOrDefault();

        if (activeApointment is not null)
        {
            await _apointmentRepository.UpdateStatusAsync(activeApointment.Id, "Transferred");
        }

        await ScheduleAppointmentAsync(patientId, newDoctorId, scheduledAt);
    }
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;
using System.Security.Cryptography;
using System.Text;

namespace Hospital.Application.Services;

public class AuthService : IAuthService
{
    private readonly IUserService _userService;

    public AuthService(IUserService userService)
    {
        _userService = userService;
    }

    public async Task<User?> LoginAsync(string username, string password)
    {
        var user = await _userService.GetByUsernameAsync(username);
        if (user is null)
        {
            return null;
        }

        if (!VerifyPassword(password, user.Password))
        {
            return null;
        }

        return user;
    }

    public async Task RegisterAsync(string username, string password, string role)
    {
        if (string.IsNullOrWhiteSpace(username))
        {
            throw new ArgumentException("Username is required.", nameof(username));
        }


        var existingUser = await _userService.GetByUsernameAsync(username);
        if (existingUser is not null)
        {
            throw new InvalidOperationException("User with this username already exists.");
        }

        var user = new User
        {
            Username = username,
            Password = HashPassword(password),
            Role = role
        };

        await _userService.AddAsync(user);
    }

    private static string HashPassword(string password)
    {
        var passwordBytes = Encoding.UTF8.GetBytes(password);
        var hashBytes = SHA256.HashData(passwordBytes);
        return Convert.ToBase64String(hashBytes);
    }

    private static bool VerifyPassword(string password, string passwordHash)
    {
        if (string.IsNullOrWhiteSpace(passwordHash))
        {
            return false;
        }

        byte[] expectedHash;

        try
        {
            expectedHash = Convert.FromBase64String(passwordHash);
        }
        catch (FormatException)
        {
            return false;
        }

        var actualHash = SHA256.HashData(Encoding.UTF8.GetBytes(password));

        if (actualHash.Length != expectedHash.Length)
        {
            return false;
        }

        return CryptographicOperations.FixedTimeEquals(actualHash, expectedHash);
    }
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;
using System.Security.Cryptography;
using System.Text;

namespace Hospital.Application.Services;

public class AuthService : IAuthService
{
    private static readonly HashSet<string> AllowedRoles = new(StringComparer.OrdinalIgnoreCase)
    {
        "Admin",
        "Doctor"
    };

    private readonly IUserService _userService;

    public AuthService(IUserService userService)
    {
        _userService = userService;
    }

    public async Task<User?> LoginAsync(string username, string password)
    {
        if (string.IsNullOrWhiteSpace(username) || string.IsNullOrWhiteSpace(password))
        {
            return null;
        }

        var normalizedUsername = username.Trim();
        var user = await _userService.GetByUsernameAsync(normalizedUsername);
        if (user is null)
        {
            return null;
        }

        if (!VerifyPassword(password, user.Password))
        {
            return null;
        }

        return user;
    }

    public async Task RegisterAsync(string username, string password, string role)
    {
        if (string.IsNullOrWhiteSpace(username))
        {
            throw new ArgumentException("Username is required.", nameof(username));
        }

        if (string.IsNullOrWhiteSpace(password))
        {
            throw new ArgumentException("Password is required.", nameof(password));
        }

        if (password.Length < 6)
        {
            throw new ArgumentException("Password must be at least 6 characters.", nameof(password));
        }

        if (string.IsNullOrWhiteSpace(role))
        {
            throw new ArgumentException("Role is required.", nameof(role));
        }

        var normalizedUsername = username.Trim();
        var normalizedRole = role.Trim();

        if (!AllowedRoles.Contains(normalizedRole))
        {
            throw new ArgumentException("Role must be Admin or Doctor.", nameof(role));
        }

        var existingUser = await _userService.GetByUsernameAsync(normalizedUsername);
        if (existingUser is not null)
        {
            throw new InvalidOperationException("User with this username already exists.");
        }

        var user = new User
        {
            Username = normalizedUsername,
            Password = HashPassword(password),
            Role = normalizedRole
        };

        await _userService.AddAsync(user);
    }

    private static string HashPassword(string password)
    {
        var passwordBytes = Encoding.UTF8.GetBytes(password);
        var hashBytes = SHA256.HashData(passwordBytes);
        return Convert.ToBase64String(hashBytes);
    }

    private static bool VerifyPassword(string password, string passwordHash)
    {
        if (string.IsNullOrWhiteSpace(passwordHash))
        {
            return false;
        }

        byte[] expectedHash;

        try
        {
            expectedHash = Convert.FromBase64String(passwordHash);
        }
        catch (FormatException)
        {
            return false;
        }

        var actualHash = SHA256.HashData(Encoding.UTF8.GetBytes(password));

        if (actualHash.Length != expectedHash.Length)
        {
            return false;
        }

        return CryptographicOperations.FixedTimeEquals(actualHash, expectedHash);
    }
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;
using Hospital.Domain.Interfaces;

namespace Hospital.Application.Services;

public class PatientService : IPatientService
{
    private const int MaxConcurrentTasks = 4;
    private readonly IPatientRepository _patientRepository;

    public PatientService(IPatientRepository patientRepository)
    {
        _patientRepository = patientRepository;
    }

    public Task<IEnumerable<Patient>> GetAllActiveAsync()
    {
        return _patientRepository.GetAllActiveAsync();
    }

    public async Task ProcessPatientsAsync(IEnumerable<int> patientIds)
    {
        ArgumentNullException.ThrowIfNull(patientIds);

        using var semaphore = new SemaphoreSlim(MaxConcurrentTasks, MaxConcurrentTasks);
        var tasks = patientIds.Select(id => ProcessPatientAsync(id, semaphore));

        await Task.WhenAll(tasks);
    }

    private async Task ProcessPatientAsync(int patientId, SemaphoreSlim semaphore)
    {
        await semaphore.WaitAsync();
        try
        {
            var patient = await _patientRepository.GetByIdAsync(patientId);

            var delay = Random.Shared.Next(200, 501);
            await Task.Delay(delay);

            if (patient is null)
            {
                Console.WriteLine($"Patient {patientId}: not found (delay {delay} ms)");
                return;
            }

            Console.WriteLine(
                $"Patient {patientId}: {patient.FullName}, diagnosis={patient.Diagnosis}, active={patient.IsActive} (delay {delay} ms)");
        }
        finally
        {
            semaphore.Release();
        }
    }
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;
using Hospital.Domain.Interfaces;

namespace Hospital.Application.Services;

public class PatientService : IPatientService
{
    private const int MaxConcurrentTasks = 4;
    private readonly IApointmentRepository _apointmentRepository;
    private readonly IPatientRepository _patientRepository;

    public PatientService(IPatientRepository patientRepository, IApointmentRepository apointmentRepository)
    {
        _patientRepository = patientRepository;
        _apointmentRepository = apointmentRepository;
    }

    public Task<IEnumerable<Patient>> GetAllActiveAsync()
    {
        return _patientRepository.GetAllActiveAsync();
    }

    public async Task<IEnumerable<Patient>> GetActiveByDoctorIdAsync(int doctorId)
    {
        if (doctorId <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(doctorId), "DoctorId must be greater than 0.");
        }

        var apointments = await _apointmentRepository.GetByDoctorIdAsync(doctorId);
        var scheduledPatientIds = apointments
            .Where(a => string.Equals(a.Status, "Scheduled", StringComparison.OrdinalIgnoreCase))
            .Select(a => a.PatientId)
            .Distinct()
            .ToHashSet();

        if (scheduledPatientIds.Count == 0)
        {
            return Array.Empty<Patient>();
        }

        var activePatients = await _patientRepository.GetAllActiveAsync();
        return activePatients.Where(p => scheduledPatientIds.Contains(p.Id)).ToArray();
    }

    public async Task ProcessPatientsAsync(IEnumerable<int> patientIds)
    {
        ArgumentNullException.ThrowIfNull(patientIds);

        var ids = patientIds.ToArray();
        if (ids.Length == 0)
        {
            throw new ArgumentException("At least one patient id is required.", nameof(patientIds));
        }

        if (ids.Any(id => id <= 0))
        {
            throw new ArgumentException("Patient ids must be greater than 0.", nameof(patientIds));
        }

        using var semaphore = new SemaphoreSlim(MaxConcurrentTasks, MaxConcurrentTasks);
        var tasks = ids.Select(id => ProcessPatientAsync(id, semaphore));

        await Task.WhenAll(tasks);
    }

    private async Task ProcessPatientAsync(int patientId, SemaphoreSlim semaphore)
    {
        await semaphore.WaitAsync();
        try
        {
            var patient = await _patientRepository.GetByIdAsync(patientId);

            var delay = Random.Shared.Next(200, 501);
            await Task.Delay(delay);

            if (patient is null)
            {
                Console.WriteLine($"Patient {patientId}: not found (delay {delay} ms)");
                return;
            }

            Console.WriteLine(
                $"Patient {patientId}: {patient.FullName}, diagnosis={patient.Diagnosis}, active={patient.IsActive} (delay {delay} ms)");
        }
        finally
        {
            semaphore.Release();
        }
    }
}

using Hospital.Application.Interfaces;
using Hospital.Application.Services;
using Hospital.ConsoleApp.Menus;
using Hospital.Domain.Interfaces;
using Hospital.infrastructure.Persistence.Data;
using Hospital.infrastructure.Repositories;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;

namespace Hospital.ConsoleApp.DI;

public static class DependencyInjection
{
    public static IServiceCollection AddHospitalDependencies(this IServiceCollection services)
    {
        services.AddDbContext<AppDbContext>(options =>
            options.UseSqlServer("Server=localhost;Database=HospitalDb;Trusted_Connection=True;TrustServerCertificate=True"));

        services.AddScoped<IApointmentService, ApointmentService>();
        services.AddScoped<IDoctorService, DoctorService>();
        services.AddScoped<IPatientService, PatientService>();
        services.AddScoped<IUserService, UserService>();
        services.AddScoped<IAuthService, AuthService>();


        services.AddScoped<IApointmentRepository, ApointmentRepository>();
        services.AddScoped<IDoctorRepository, DoctorRepository>();
        services.AddScoped<IPatientRepository, PatientRepository>();
        services.AddScoped<IUserRepository, UserRepository>();
        services.AddScoped<MainMenuHandler>();

        return services;
    }
}

