using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;

namespace Hospital.ConsoleApp.MenuActions;

public class MenuActionsHandler : IMenuActions
{
    private readonly IAuthService _authService;
    private readonly IPatientService _patientService;
    private readonly IApointmentService _apointmentService;
    private User? _currentUser;

    public MenuActionsHandler(
        IAuthService authService,
        IPatientService patientService,
        IApointmentService apointmentService)
    {
        _authService = authService;
        _patientService = patientService;
        _apointmentService = apointmentService;
    }

    public async Task LoginAsync()
    {
        Console.Write("Username: ");
        var username = Console.ReadLine() ?? string.Empty;
        Console.Write("Password: ");
        var password = Console.ReadLine() ?? string.Empty;

        var user = await _authService.LoginAsync(username, password);
        if (user is null)
        {
            Console.WriteLine("Invalid username or password.");
            return;
        }

        _currentUser = user;
        Console.WriteLine($"Logged in as {_currentUser.Username} ({_currentUser.Role})");
    }

    public async Task RegisterAsync()
    {
        Console.Write("Username: ");
        var username = Console.ReadLine() ?? string.Empty;
        Console.Write("Password: ");
        var password = Console.ReadLine() ?? string.Empty;
        Console.Write("Role: ");
        var role = Console.ReadLine() ?? "Doctor";

        try
        {
            await _authService.RegisterAsync(username, password, role);
            Console.WriteLine("User registered.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Register failed: {ex.Message}");
        }
    }

    public async Task ShowPatientsAsync()
    {
        var patients = await _patientService.GetAllActiveAsync();
        foreach (var patient in patients)
        {
            Console.WriteLine($"[{patient.Id}] {patient.FullName}, diagnosis={patient.Diagnosis}, active={patient.IsActive}");
        }
    }

    public async Task ScheduleAppointmentAsync()
    {
        if (!TryReadInt("PatientId", out var patientId) || !TryReadInt("DoctorId", out var doctorId))
        {
            return;
        }

        var scheduledAt = ReadDateTimeOrNow();

        try
        {
            await _apointmentService.ScheduleAppointmentAsync(patientId, doctorId, scheduledAt);
            Console.WriteLine("Appointment scheduled.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Schedule failed: {ex.Message}");
        }
    }

    public async Task TransferPatientAsync()
    {
        if (!TryReadInt("PatientId", out var patientId) || !TryReadInt("NewDoctorId", out var newDoctorId))
        {
            return;
        }

        var scheduledAt = ReadDateTimeOrNow();

        try
        {
            await _apointmentService.TransferPatientAsync(patientId, newDoctorId, scheduledAt);
            Console.WriteLine("Patient transferred.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Transfer failed: {ex.Message}");
        }
    }

    public async Task ProcessPatientsAsync()
    {
        Console.Write("Patient IDs (comma-separated): ");
        var raw = Console.ReadLine() ?? string.Empty;
        var ids = raw
            .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(x => int.TryParse(x, out var id) ? id : (int?)null)
            .Where(x => x.HasValue)
            .Select(x => x!.Value)
            .ToArray();

        if (ids.Length == 0)
        {
            Console.WriteLine("No valid IDs provided.");
            return;
        }

        await _patientService.ProcessPatientsAsync(ids);
    }

    private static bool TryReadInt(string field, out int value)
    {
        Console.Write($"{field}: ");
        var raw = Console.ReadLine();
        if (!int.TryParse(raw, out value))
        {
            Console.WriteLine($"Invalid {field}.");
            return false;
        }

        return true;
    }

    private static DateTime ReadDateTimeOrNow()
    {
        Console.Write("ScheduledAt (yyyy-MM-dd HH:mm, empty=now): ");
        var raw = Console.ReadLine();
        if (DateTime.TryParse(raw, out var dateTime))
        {
            return dateTime;
        }

        return DateTime.Now;
    }
}

using Hospital.Application.Interfaces;
using Hospital.Domain.Entities;

namespace Hospital.ConsoleApp.MenuActions;

public class MenuActionsHandler : IMenuActions
{
    private const string AdminRole = "Admin";
    private const string DoctorRole = "Doctor";

    private readonly IAuthService _authService;
    private readonly IPatientService _patientService;
    private readonly IApointmentService _apointmentService;
    private User? _currentUser;

    public bool IsLoggedIn => _currentUser is not null;
    public bool IsAdmin => string.Equals(_currentUser?.Role, AdminRole, StringComparison.OrdinalIgnoreCase);
    public bool IsDoctor => string.Equals(_currentUser?.Role, DoctorRole, StringComparison.OrdinalIgnoreCase);
    public string? CurrentUsername => _currentUser?.Username;

    public MenuActionsHandler(
        IAuthService authService,
        IPatientService patientService,
        IApointmentService apointmentService)
    {
        _authService = authService;
        _patientService = patientService;
        _apointmentService = apointmentService;
    }

    public async Task LoginAsync()
    {
        Console.Write("Username: ");
        var username = (Console.ReadLine() ?? string.Empty).Trim();
        Console.Write("Password: ");
        var password = Console.ReadLine() ?? string.Empty;

        if (string.IsNullOrWhiteSpace(username) || string.IsNullOrWhiteSpace(password))
        {
            Console.WriteLine("Username and password are required.");
            return;
        }

        var user = await _authService.LoginAsync(username, password);
        if (user is null)
        {
            Console.WriteLine("Invalid username or password.");
            return;
        }

        _currentUser = user;
        Console.WriteLine($"Logged in as {_currentUser.Username} ({_currentUser.Role})");
    }

    public Task LogoutAsync()
    {
        if (_currentUser is null)
        {
            Console.WriteLine("You are not logged in.");
            return Task.CompletedTask;
        }

        Console.WriteLine($"User '{_currentUser.Username}' logged out.");
        _currentUser = null;
        return Task.CompletedTask;
    }

    public async Task RegisterAsync()
    {
        if (!CanExecuteAdminOperation("Register"))
        {
            return;
        }

        Console.Write("Username: ");
        var username = (Console.ReadLine() ?? string.Empty).Trim();
        Console.Write("Password: ");
        var password = Console.ReadLine() ?? string.Empty;
        Console.Write("Role: ");
        var roleInput = Console.ReadLine();
        var role = string.IsNullOrWhiteSpace(roleInput) ? "Doctor" : roleInput.Trim();

        if (string.IsNullOrWhiteSpace(username) || string.IsNullOrWhiteSpace(password))
        {
            Console.WriteLine("Username and password are required.");
            return;
        }

        try
        {
            await _authService.RegisterAsync(username, password, role);
            Console.WriteLine("User registered.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Register failed: {ex.Message}");
        }
    }

    public async Task ShowPatientsAsync()
    {
        if (!EnsureLoggedIn())
        {
            return;
        }

        IEnumerable<Patient> patients;
        if (IsAdmin)
        {
            patients = await _patientService.GetAllActiveAsync();
        }
        else if (IsDoctor)
        {
            // Assumption: User.Id corresponds to Doctor.Id for access scoping.
            patients = await _patientService.GetActiveByDoctorIdAsync(_currentUser!.Id);
        }
        else
        {
            Console.WriteLine("Access denied.");
            return;
        }

        foreach (var patient in patients)
        {
            Console.WriteLine($"[{patient.Id}] {patient.FullName}, diagnosis={patient.Diagnosis}, active={patient.IsActive}");
        }
    }

    public async Task ScheduleAppointmentAsync()
    {
        if (!CanExecuteAdminOperation("Schedule Appointment"))
        {
            return;
        }

        if (!TryReadPositiveInt("PatientId", out var patientId) || !TryReadPositiveInt("DoctorId", out var doctorId))
        {
            return;
        }

        if (!TryReadDateTimeOrNow(out var scheduledAt))
        {
            return;
        }

        try
        {
            await _apointmentService.ScheduleAppointmentAsync(patientId, doctorId, scheduledAt);
            Console.WriteLine("Appointment scheduled.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Schedule failed: {ex.Message}");
        }
    }

    public async Task TransferPatientAsync()
    {
        if (!CanExecuteAdminOperation("Transfer Patient"))
        {
            return;
        }

        if (!TryReadPositiveInt("PatientId", out var patientId) || !TryReadPositiveInt("NewDoctorId", out var newDoctorId))
        {
            return;
        }

        if (!TryReadDateTimeOrNow(out var scheduledAt))
        {
            return;
        }

        try
        {
            await _apointmentService.TransferPatientAsync(patientId, newDoctorId, scheduledAt);
            Console.WriteLine("Patient transferred.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Transfer failed: {ex.Message}");
        }
    }

    public async Task ProcessPatientsAsync()
    {
        if (!CanExecuteAdminOperation("Process Patients"))
        {
            return;
        }

        Console.Write("Patient IDs (comma-separated): ");
        var raw = Console.ReadLine() ?? string.Empty;
        var ids = raw
            .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(x => int.TryParse(x, out var id) ? id : (int?)null)
            .Where(x => x.HasValue)
            .Select(x => x!.Value)
            .Where(id => id > 0)
            .ToArray();

        if (ids.Length == 0)
        {
            Console.WriteLine("No valid IDs provided.");
            return;
        }

        await _patientService.ProcessPatientsAsync(ids);
    }

    private bool CanExecuteAdminOperation(string operationName)
    {
        if (!EnsureLoggedIn())
        {
            return false;
        }

        if (!IsAdmin)
        {
            Console.WriteLine($"Access denied for '{operationName}'. Admin role required.");
            return false;
        }

        return true;
    }

    private bool EnsureLoggedIn()
    {
        if (_currentUser is not null)
        {
            return true;
        }

        Console.WriteLine("Please login first.");
        return false;
    }

    private static bool TryReadPositiveInt(string field, out int value)
    {
        Console.Write($"{field}: ");
        var raw = Console.ReadLine();
        if (!int.TryParse(raw, out value) || value <= 0)
        {
            Console.WriteLine($"Invalid {field}. Must be a positive integer.");
            return false;
        }

        return true;
    }

    private static bool TryReadDateTimeOrNow(out DateTime value)
    {
        Console.Write("ScheduledAt (yyyy-MM-dd HH:mm, empty=now): ");
        var raw = Console.ReadLine();
        if (string.IsNullOrWhiteSpace(raw))
        {
            value = DateTime.Now;
            return true;
        }

        if (DateTime.TryParse(raw, out var dateTime))
        {
            value = dateTime;
            return true;
        }

        Console.WriteLine("Invalid datetime format.");
        value = default;
        return false;
    }
}

using Hospital.ConsoleApp.MenuActions;

namespace Hospital.ConsoleApp.Menus;

public class MainMenuHandler
{
    private readonly IMenuActions _menuActions;

    public MainMenuHandler(IMenuActions menuActions)
    {
        _menuActions = menuActions;
    }

    public async Task RunAsync()
    {
        while (true)
        {
            PrintMenu();
            Console.Write("Select option: ");
            var option = Console.ReadLine()?.Trim();

            switch (option)
            {
                case "1":
                    await _menuActions.LoginAsync();
                    break;
                case "2":
                    await _menuActions.RegisterAsync();
                    break;
                case "3":
                    await _menuActions.ShowPatientsAsync();
                    break;
                case "4":
                    await _menuActions.ScheduleAppointmentAsync();
                    break;
                case "5":
                    await _menuActions.TransferPatientAsync();
                    break;
                case "6":
                    await _menuActions.ProcessPatientsAsync();
                    break;
                case "7":
                    Console.WriteLine("Bye.");
                    return;
                default:
                    Console.WriteLine("Unknown option.");
                    break;
            }

            Console.WriteLine();
        }
    }

    private static void PrintMenu()
    {
        Console.WriteLine("===== Hospital Menu =====");
        Console.WriteLine("1. Login");
        Console.WriteLine("2. Register");
        Console.WriteLine("3. Show Patients");
        Console.WriteLine("4. Schedule Appointment");
        Console.WriteLine("5. Transfer Patient");
        Console.WriteLine("6. Process Patients");
        Console.WriteLine("7. Exit");
    }
}

using Hospital.ConsoleApp.MenuActions;

namespace Hospital.ConsoleApp.Menus;

public class MainMenuHandler
{
    private readonly IMenuActions _menuActions;

    public MainMenuHandler(IMenuActions menuActions)
    {
        _menuActions = menuActions;
    }

    public async Task RunAsync()
    {
        while (true)
        {
            PrintPanel();
            Console.Write("Select option: ");
            var option = Console.ReadLine()?.Trim();

            var shouldExit = await HandleOptionAsync(option);
            if (shouldExit)
            {
                Console.WriteLine("Bye.");
                return;
            }

            Console.WriteLine();
        }
    }

    private void PrintPanel()
    {
        if (!_menuActions.IsLoggedIn)
        {
            PrintGuestPanel();
            return;
        }

        if (_menuActions.IsAdmin)
        {
            PrintAdminPanel();
            return;
        }

        if (_menuActions.IsDoctor)
        {
            PrintDoctorPanel();
            return;
        }

        PrintUnknownRolePanel();
    }

    private async Task<bool> HandleOptionAsync(string? option)
    {
        if (!_menuActions.IsLoggedIn)
        {
            return await HandleGuestOptionAsync(option);
        }

        if (_menuActions.IsAdmin)
        {
            return await HandleAdminOptionAsync(option);
        }

        if (_menuActions.IsDoctor)
        {
            return await HandleDoctorOptionAsync(option);
        }

        Console.WriteLine("Unknown role. Please login again.");
        await _menuActions.LogoutAsync();
        return false;
    }

    private static void PrintGuestPanel()
    {
        Console.WriteLine("===== Guest Panel =====");
        Console.WriteLine("1. Login");
        Console.WriteLine("2. Exit");
    }

    private void PrintAdminPanel()
    {
        Console.WriteLine($"===== Admin Panel ({_menuActions.CurrentUsername}) =====");
        Console.WriteLine("1. Register");
        Console.WriteLine("2. Show Patients");
        Console.WriteLine("3. Schedule Appointment");
        Console.WriteLine("4. Transfer Patient");
        Console.WriteLine("5. Process Patients");
        Console.WriteLine("6. Logout");
        Console.WriteLine("7. Exit");
    }

    private void PrintDoctorPanel()
    {
        Console.WriteLine($"===== Doctor Panel ({_menuActions.CurrentUsername}) =====");
        Console.WriteLine("1. Show My Patients");
        Console.WriteLine("2. Logout");
        Console.WriteLine("3. Exit");
    }

    private static void PrintUnknownRolePanel()
    {
        Console.WriteLine("===== Unknown Role Panel =====");
        Console.WriteLine("1. Logout");
        Console.WriteLine("2. Exit");
    }

    private async Task<bool> HandleGuestOptionAsync(string? option)
    {
        switch (option)
        {
            case "1":
                await _menuActions.LoginAsync();
                return false;
            case "2":
                return true;
            default:
                Console.WriteLine("Unknown option.");
                return false;
        }
    }

    private async Task<bool> HandleAdminOptionAsync(string? option)
    {
        switch (option)
        {
            case "1":
                await _menuActions.RegisterAsync();
                return false;
            case "2":
                await _menuActions.ShowPatientsAsync();
                return false;
            case "3":
                await _menuActions.ScheduleAppointmentAsync();
                return false;
            case "4":
                await _menuActions.TransferPatientAsync();
                return false;
            case "5":
                await _menuActions.ProcessPatientsAsync();
                return false;
            case "6":
                await _menuActions.LogoutAsync();
                return false;
            case "7":
                return true;
            default:
                Console.WriteLine("Unknown option.");
                return false;
        }
    }

    private async Task<bool> HandleDoctorOptionAsync(string? option)
    {
        switch (option)
        {
            case "1":
                await _menuActions.ShowPatientsAsync();
                return false;
            case "2":
                await _menuActions.LogoutAsync();
                return false;
            case "3":
                return true;
            default:
                Console.WriteLine("Unknown option.");
                return false;
        }
    }
}

using Hospital.Domain.Entities;

namespace Hospital.Domain.Interfaces;

public interface IApointmentRepository
{
    Task<IEnumerable<Apointment>> GetByPatientIdAsync(int patientId);
    Task<bool> DoctorHasAppointmentAsync(int doctorId, DateTime at);
    Task AddAsync(Apointment apointment);
    Task UpdateStatusAsync(int apointmentId, string status);
}

using Hospital.Domain.Entities;

namespace Hospital.Domain.Interfaces;

public interface IApointmentRepository
{
    Task<IEnumerable<Apointment>> GetByPatientIdAsync(int patientId);
    Task<IEnumerable<Apointment>> GetByDoctorIdAsync(int doctorId);
    Task<bool> DoctorHasAppointmentAsync(int doctorId, DateTime at);
    Task AddAsync(Apointment apointment);
    Task UpdateStatusAsync(int apointmentId, string status);
}

using Hospital.Domain.Entities;
using Hospital.Domain.Interfaces;
using Hospital.infrastructure.Persistence.Data;
using Microsoft.EntityFrameworkCore;

namespace Hospital.infrastructure.Repositories;

public class ApointmentRepository : IApointmentRepository
{
    private readonly AppDbContext _context;
    private static readonly SemaphoreSlim UpdateStatusLock = new(1, 1);

    public ApointmentRepository(AppDbContext context)
    {
        _context = context;
    }

    public async Task<IEnumerable<Apointment>> GetByPatientIdAsync(int patientId)
    {
        return await _context.Apointments
            .AsNoTracking()
            .Where(a => a.PatientId == patientId)
            .ToListAsync();
    }


    public async Task<bool> DoctorHasAppointmentAsync(int doctorId, DateTime at)
    {
        return await _context.Apointments
            .AsNoTracking()
            .AnyAsync(a => a.DoctorId == doctorId && a.ScheduledAt == at);
    }

    public async Task AddAsync(Apointment apointment)
    {
        _context.Apointments.Add(apointment);
        await _context.SaveChangesAsync();
    }

    public async Task UpdateStatusAsync(int apointmentId, string status)
    {
        await UpdateStatusLock.WaitAsync();
        try
        {
            await _context.Apointments
                .Where(a => a.Id == apointmentId)
                .ExecuteUpdateAsync(s => s.SetProperty(a => a.Status, status));
        }
        finally {
            UpdateStatusLock.Release();
        }

    }
}

